document.addEventListener('DOMContentLoaded', () => {
    const form = document.getElementById('movie-search-form');
    const input = document.getElementById('movie-search-input');
    const region = document.getElementById('movie-search-region');
    const year = document.getElementById('movie-search-year');
    const type = document.getElementById('movie-search-type');
    const status = document.getElementById('movie-search-status');
    const results = document.getElementById('movie-search-results');

    if (!form || !input || !region || !year || !type || !status || !results) {
        return;
    }

    const params = new URLSearchParams(window.location.search);
    const initialQuery = params.get('q') || '';
    input.value = initialQuery;

    const fillSelect = (select, values) => {
        values.forEach((value) => {
            const option = document.createElement('option');
            option.value = value;
            option.textContent = value;
            select.appendChild(option);
        });
    };

    fillSelect(region, Array.from(new Set(MOVIE_SEARCH_INDEX.map((movie) => movie.region))).sort());
    fillSelect(year, Array.from(new Set(MOVIE_SEARCH_INDEX.map((movie) => String(movie.year)))).sort((a, b) => Number(b) - Number(a)));
    fillSelect(type, Array.from(new Set(MOVIE_SEARCH_INDEX.map((movie) => movie.type))).sort());

    const createCard = (movie) => {
        const article = document.createElement('article');
        article.className = 'movie-card';
        article.innerHTML = `
            <a class="movie-card__poster" href="${movie.url}" aria-label="${escapeHtml(movie.title)} 在线观看">
                <img src="${movie.cover}" alt="${escapeHtml(movie.title)}" loading="lazy">
                <span class="movie-card__play">▶</span>
            </a>
            <div class="movie-card__body">
                <div class="movie-card__meta">${escapeHtml(movie.region)} · ${movie.year} · ${escapeHtml(movie.type)}</div>
                <h3><a href="${movie.url}">${escapeHtml(movie.title)}</a></h3>
                <p>${escapeHtml(truncate(movie.description, 72))}</p>
                <div class="movie-card__tags"><span>${escapeHtml(movie.genre)}</span></div>
            </div>
        `;
        return article;
    };

    const escapeHtml = (value) => String(value || '')
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#039;');

    const truncate = (value, length) => {
        const text = String(value || '').trim();
        return text.length > length ? `${text.slice(0, length - 1)}…` : text;
    };

    const render = () => {
        const keyword = input.value.trim().toLowerCase();
        const regionValue = region.value;
        const yearValue = year.value;
        const typeValue = type.value;

        const matches = MOVIE_SEARCH_INDEX.filter((movie) => {
            const haystack = [
                movie.title,
                movie.region,
                movie.type,
                movie.year,
                movie.genre,
                movie.tags.join(' '),
                movie.description
            ].join(' ').toLowerCase();

            return (!keyword || haystack.includes(keyword)) &&
                (!regionValue || movie.region === regionValue) &&
                (!yearValue || String(movie.year) === yearValue) &&
                (!typeValue || movie.type === typeValue);
        }).slice(0, 120);

        results.innerHTML = '';
        matches.forEach((movie) => results.appendChild(createCard(movie)));

        if (matches.length === 0) {
            status.textContent = '没有找到匹配影片。';
            return;
        }

        status.textContent = `已显示 ${matches.length} 条结果。`;
    };

    form.addEventListener('submit', (event) => {
        event.preventDefault();
        render();
    });

    input.addEventListener('input', render);
    region.addEventListener('change', render);
    year.addEventListener('change', render);
    type.addEventListener('change', render);

    render();
});
